SELECT ID, COMPANY_NAME, COMPANY_ID, DEPT_NAME, DEPT_ID, WORK_PROCESS_ID, WORK_PROCESS_NAME, WORK_PROCESS_CHILD_ID, WORK_PROCESS_CHILD_NAME, SALARY_TYPE_CODE,SALARY_TYPE_NAME, PRICE, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME FROM M_PIECE_PRICE
and ID = #{id}
and COMPANY_ID = #{companyId}
and DEPT_ID = #{deptId}
and WORK_PROCESS_ID = #{workProcessId}
and WORK_PROCESS_CHILD_ID = #{workProcessChildId}
